#include <stdio.h>
#include <string.h>
#include <stdlib.h>

#define N 100
#define M 10000
#define Q 100

int n, m, q, X, cnt[N][N][N][101], ans, i, j, k, u, v, w;

int main() {
    scanf("%d %d", &n, &m);
    for (i = 0; i < m; i++) {
        scanf("%d %d %d", &u, &v, &w);
        for (j = 0; j < n; j++) {
            for (k = 0; k < n; k++) {
                cnt[j][k][u][w] += cnt[j][k][v][w];
                cnt[j][k][v][w] += cnt[j][k][u][w];
            }
        }
    }
    scanf("%d", &q);
    while (q--) {
        scanf("%d", &X);
        ans = 0;
        for (i = 0; i < n; i++) {
            for (j = 0; j < n; j++) {
                ans += cnt[i][j][i][X];
            }
        }
        printf("%d\n", ans);
    }
    return 0;
}

